1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: AXI-Lite 1GbE Register Interface
5	-------------------------------------------------------------------------------
6	-- This file is part of 'SLAC Firmware Standard Library'.
7	-- It is subject to the license terms in the LICENSE.txt file found in the
8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiLitePkg.all;
24	use surf.EthMacPkg.all;
25	use surf.GigEthPkg.all;
26	
27	entity GigEthReg is
28	   generic (
29	      TPD_G        : time    := 1 ns;
30	      EN_AXI_REG_G : boolean := false);
31	   port (
32	      -- Local Configurations
33	      localMac       : in  slv(47 downto 0) := MAC_ADDR_INIT_C;
34	      -- Clocks and resets
35	      clk            : in  sl;
36	      rst            : in  sl;
37	      -- AXI-Lite Register Interface
38	      axiReadMaster  : in  AxiLiteReadMasterType;
39	      axiReadSlave   : out AxiLiteReadSlaveType;
40	      axiWriteMaster : in  AxiLiteWriteMasterType;
41	      axiWriteSlave  : out AxiLiteWriteSlaveType;
42	      -- Configuration and Status Interface
43	      config         : out GigEthConfigType;
44	      status         : in  GigEthStatusType);
45	end GigEthReg;
46	
47	architecture rtl of GigEthReg is
48	
49	   constant STATUS_SIZE_C : positive := 32;
50	
51	   type RegType is record
52	      hardRst       : sl;
53	      cntRst        : sl;
54	      rollOverEn    : slv(STATUS_SIZE_C-1 downto 0);
55	      config        : GigEthConfigType;
56	      axiReadSlave  : AxiLiteReadSlaveType;
57	      axiWriteSlave : AxiLiteWriteSlaveType;
58	   end record RegType;
59	
60	   constant REG_INIT_C : RegType := (
61	      hardRst       => '0',
62	      cntRst        => '1',
63	      rollOverEn    => (others => '0'),
64	      config        => GIG_ETH_CONFIG_INIT_C,
65	      axiReadSlave  => AXI_LITE_READ_SLAVE_INIT_C,
66	      axiWriteSlave => AXI_LITE_WRITE_SLAVE_INIT_C);
67	
68	   signal r   : RegType := REG_INIT_C;
69	   signal rin : RegType;
70	
71	   signal statusOut    : slv(STATUS_SIZE_C-1 downto 0);
72	   signal cntOut       : SlVectorArray(STATUS_SIZE_C-1 downto 0, 31 downto 0);
73	   signal localMacSync : slv(47 downto 0);
74	   signal wdtRst       : sl;
75	
76	begin
77	
78	   U_WatchDogRst : entity surf.WatchDogRst
79	      generic map(
80	         TPD_G      => TPD_G,
81	         DURATION_G => getTimeRatio(125.0E+6, 0.5))
82	      port map (
83	         clk    => clk,
84	         monIn  => status.phyReady,
85	         rstOut => wdtRst);
86	
87	   Sync_Config : entity surf.SynchronizerVector
88	      generic map (
89	         TPD_G   => TPD_G,
90	         WIDTH_G => 48)
91	      port map (
92	         clk     => clk,
93	         dataIn  => localMac,
94	         dataOut => localMacSync);
95	
96	   GEN_BYPASS : if (EN_AXI_REG_G = false) generate
97	
98	      axiReadSlave  <= AXI_LITE_READ_SLAVE_EMPTY_DECERR_C;
99	      axiWriteSlave <= AXI_LITE_WRITE_SLAVE_EMPTY_DECERR_C;
100	
101	      process (localMacSync, wdtRst) is
102	         variable retVar : GigEthConfigType;
103	      begin
104	         retVar                      := GIG_ETH_CONFIG_INIT_C;
105	         retVar.macConfig.macAddress := localMacSync;
106	         retVar.softRst              := wdtRst;
107	         config                      <= retVar;
108	      end process;
109	
110	   end generate;
111	
112	   GEN_REG : if (EN_AXI_REG_G = true) generate
113	
114	      SyncStatusVec_Inst : entity surf.SyncStatusVector
115	         generic map (
116	            TPD_G          => TPD_G,
117	            OUT_POLARITY_G => '1',
118	            CNT_RST_EDGE_G => false,
119	            COMMON_CLK_G   => true,
120	            CNT_WIDTH_G    => 32,
121	            WIDTH_G        => STATUS_SIZE_C)
122	         port map (
123	            -- Input Status bit Signals (wrClk domain)
124	            statusIn(0)           => status.phyReady,
125	            statusIn(1)           => status.macStatus.rxPauseCnt,
126	            statusIn(2)           => status.macStatus.txPauseCnt,
127	            statusIn(3)           => status.macStatus.rxCountEn,
128	            statusIn(4)           => status.macStatus.rxOverFlow,
129	            statusIn(5)           => status.macStatus.rxCrcErrorCnt,
130	            statusIn(6)           => status.macStatus.txCountEn,
131	            statusIn(7)           => status.macStatus.txUnderRunCnt,
132	            statusIn(8)           => status.macStatus.txNotReadyCnt,
133	            statusIn(31 downto 9) => (others => '0'),
134	            -- Output Status bit Signals (rdClk domain)
135	            statusOut             => statusOut,
136	            -- Status Bit Counters Signals (rdClk domain)
137	            cntRstIn              => r.cntRst,
138	            rollOverEnIn          => r.rollOverEn,
139	            cntOut                => cntOut,
140	            -- Clocks and Reset Ports
141	            wrClk                 => clk,
142	            rdClk                 => clk);
143	
144	      -------------------------------
145	      -- Configuration Register
146	      -------------------------------
147	      comb : process (axiReadMaster, axiWriteMaster, cntOut, localMacSync, r,
148	                      rst, status, statusOut, wdtRst) is
149	         variable v      : RegType;
150	         variable regCon : AxiLiteEndPointType;
151	         variable i      : natural;
152	      begin
153	         -- Latch the current value
154	         v := r;
155	
156	         -- Determine the transaction type
157	         axiSlaveWaitTxn(regCon, axiWriteMaster, axiReadMaster, v.axiWriteSlave, v.axiReadSlave);
158	
159	         -- Reset strobe signals
160	         v.cntRst         := '0';
161	         v.hardRst        := '0';
162	         v.config.softRst := wdtRst;
163	
164	         -- Register Mapping
165	         for i in STATUS_SIZE_C-1 downto 0 loop
166	            axiSlaveRegisterR(regCon, toSlv(4*i, 12), 0, muxSlVectorArray(cntOut, i));
167	         end loop;
168	         axiSlaveRegisterR(regCon, x"100", 0, statusOut);
169	         --axiSlaveRegisterR(regCon,x"104", 0, status.macStatus.rxPauseValue);
170	         axiSlaveRegisterR(regCon, x"108", 0, status.coreStatus);
171	
172	         axiSlaveRegister(regCon, x"200", 0, v.config.macConfig.macAddress(31 downto 0));
173	         axiSlaveRegister(regCon, x"204", 0, v.config.macConfig.macAddress(47 downto 32));
174	         --axiSlaveRegister(regCon,x"208", 0, v.config.macConfig.byteSwap);
175	
176	         --axiSlaveRegister(regCon,x"210", 0, v.config.macConfig.txShift);
177	         --axiSlaveRegister(regCon,x"214", 0, v.config.macConfig.txShiftEn);
178	         --axiSlaveRegister(regCon, x"218", 0, v.config.macConfig.interFrameGap);
179	         axiSlaveRegisterR(regCon, x"21C", 0, r.config.macConfig.pauseTime);
180	
181	         --axiSlaveRegister(regCon,x"220", 0, v.config.macConfig.rxShift);
182	         --axiSlaveRegister(regCon,x"224", 0, v.config.macConfig.rxShiftEn);
183	         axiSlaveRegisterR(regCon, x"228", 0, r.config.macConfig.filtEnable);
184	         axiSlaveRegisterR(regCon, x"22C", 0, r.config.macConfig.pauseEnable);
185	
186	         axiSlaveRegister(regCon, x"800", 0, v.config.macConfig.pauseThresh);
187	
188	         axiSlaveRegister(regCon, x"F00", 0, v.rollOverEn);
